def _now():
    return datetime.utcnow().isoformat() + "Z"

def _uuid():
    return str(uuid.uuid4())

def _safe_join(base: str, *paths: str) -> str:
    p = os.path.abspath(os.path.join(base, *paths))
    if not p.startswith(os.path.abspath(base) + os.sep) and p != os.path.abspath(base):
        raise ValueError("Unsafe path")
    return p

def _sha256_file(path: str) -> str:
    import hashlib
    h = hashlib.sha256()
    with open(path, "rb") as f:
        for chunk in iter(lambda: f.read(1024 * 1024), b""):
            h.update(chunk)
    return h.hexdigest()

def _read_upload_to_disk(upload: UploadFile, dest_path: str) -> int:
    size = 0
    with open(dest_path, "wb") as out:
        while True:
            chunk = upload.file.read(1024 * 1024)
            if not chunk:
                break
            size += len(chunk)
            if size > MAX_UPLOAD_BYTES:
                raise HTTPException(status_code=413, detail="Upload too large")
            out.write(chunk)
    return size

def _is_image_file(path: str) -> bool:
    ext = os.path.splitext(path)[1].lower()
    return ext in ALLOWED_IMAGE_EXTS

def _load_csv_from_path(csv_path: str) -> pd.DataFrame:
    df = pd.read_csv(csv_path)
    if df.empty:
        raise ValueError("CSV is empty")
    cols = {c.lower(): c for c in df.columns}
    if "label" not in cols:
        raise ValueError("CSV must contain a 'label' column")
    if "image_path" in cols:
        img_col = cols["image_path"]
    elif "image" in cols:
        img_col = cols["image"]
    elif "path" in cols:
        img_col = cols["path"]
    elif "filename" in cols:
        img_col = cols["filename"]
    else:
        raise ValueError("CSV must contain an image path column: image_path/image/path/filename")
    label_col = cols["label"]
    out = df[[img_col, label_col]].copy()
    out.columns = ["image_path", "label"]
    out["image_path"] = out["image_path"].astype(str)
    out["label"] = out["label"].astype(str)
    return out

def _extract_zip(zip_path: str, dest_dir: str) -> None:
    with zipfile.ZipFile(zip_path, "r") as z:
        for member in z.infolist():
            name = member.filename
            if name.endswith("/"):
                continue
            target = _safe_join(dest_dir, name)
            os.makedirs(os.path.dirname(target), exist_ok=True)
            with z.open(member, "r") as src, open(target, "wb") as dst:
                shutil.copyfileobj(src, dst)

def _resolve_image_paths(df: pd.DataFrame, base_dir: str) -> pd.DataFrame:
    resolved = []
    for _, row in df.iterrows():
        p = row["image_path"]
        p2 = p
        if not os.path.isabs(p2):
            p2 = os.path.abspath(os.path.join(base_dir, p2))
        if not p2.startswith(os.path.abspath(base_dir) + os.sep) and p2 != os.path.abspath(base_dir):
            continue
        if not os.path.exists(p2):
            continue
        if not _is_image_file(p2):
            continue
        resolved.append((p2, row["label"]))
    out = pd.DataFrame(resolved, columns=["image_path", "label"])
    return out

def _split_assign(n: int, val_split: float, test_split: float, seed: int) -> List[str]:
    rng = np.random.default_rng(seed)
    idx = np.arange(n)
    rng.shuffle(idx)
    n_test = int(round(n * test_split))
    n_val = int(round(n * val_split))
    splits = ["train"] * n
    for i in idx[:n_test]:
        splits[i] = "test"
    for i in idx[n_test:n_test + n_val]:
        splits[i] = "val"
    return splits

def _get_labels(conn: sqlite3.Connection) -> List[str]:
    cur = conn.cursor()
    cur.execute("SELECT DISTINCT label FROM examples ORDER BY label ASC")
    return [r["label"] for r in cur.fetchall()]

def _count_examples(conn: sqlite3.Connection) -> Dict[str, int]:
    cur = conn.cursor()
    cur.execute("SELECT split, COUNT(*) AS c FROM examples GROUP BY split")
    d = {"train": 0, "val": 0, "test": 0}
    for r in cur.fetchall():
        d[r["split"]] = int(r["c"])
    cur.execute("SELECT COUNT(*) AS c FROM examples")
    d["total"] = int(cur.fetchone()["c"])
    return d

def _fetch_examples(conn: sqlite3.Connection, split: str) -> List[Tuple[str, str]]:
    cur = conn.cursor()
    cur.execute("SELECT image_path, label FROM examples WHERE split = ? ORDER BY created_at ASC", (split,))
    return [(r["image_path"], r["label"]) for r in cur.fetchall()]

def _build_dataset(pairs: List[Tuple[str, str]], label_to_idx: Dict[str, int], image_size: int, batch_size: int, training: bool, seed: int):
    paths = [p for p, _ in pairs]
    labels = [label_to_idx[l] for _, l in pairs]
    ds = tf.data.Dataset.from_tensor_slices((paths, labels))

    def _load(path, label):
        img = tf.io.read_file(path)
        img = tf.io.decode_image(img, channels=3, expand_animations=False)
        img = tf.image.convert_image_dtype(img, tf.float32)
        img = tf.image.resize(img, [image_size, image_size], method="bilinear")
        return img, tf.one_hot(label, depth=len(label_to_idx))

    ds = ds.map(_load, num_parallel_calls=tf.data.AUTOTUNE)
    if training:
        ds = ds.shuffle(min(len(paths), 4096), seed=seed, reshuffle_each_iteration=True)
        aug = tf.keras.Sequential([
            tf.keras.layers.RandomFlip("horizontal"),
            tf.keras.layers.RandomRotation(0.05),
            tf.keras.layers.RandomZoom(0.1),
            tf.keras.layers.RandomContrast(0.1),
        ])
        ds = ds.map(lambda x, y: (aug(x, training=True), y), num_parallel_calls=tf.data.AUTOTUNE)
    ds = ds.batch(batch_size).prefetch(tf.data.AUTOTUNE)
    return ds

def _build_model(num_classes: int, image_size: int, lr: float):
    inputs = tf.keras.Input(shape=(image_size, image_size, 3))
    base = tf.keras.applications.MobileNetV2(
        include_top=False,
        weights="imagenet",
        input_tensor=inputs,
        pooling="avg"
    )
    base.trainable = False
    x = tf.keras.layers.Dropout(0.2)(base.output)
    outputs = tf.keras.layers.Dense(num_classes, activation="softmax")(x)
    model = tf.keras.Model(inputs, outputs)
    model.compile(
        optimizer=tf.keras.optimizers.Adam(learning_rate=lr),
        loss="categorical_crossentropy",
        metrics=["accuracy"]
    )
    return model, base

def _fine_tune(model: tf.keras.Model, base: tf.keras.Model, lr: float):
    base.trainable = True
    for layer in base.layers[:-30]:
        layer.trainable = False
    model.compile(
        optimizer=tf.keras.optimizers.Adam(learning_rate=lr * 0.1),
        loss="categorical_crossentropy",
        metrics=["accuracy"]
    )

def _save_model_bundle(model: tf.keras.Model, model_dir: str, labels: List[str], image_size: int, metrics: Dict[str, Any]):
    os.makedirs(model_dir, exist_ok=True)
    tf.saved_model.save(model, model_dir)
    with open(os.path.join(model_dir, "labels.json"), "w", encoding="utf-8") as f:
        json.dump({"labels": labels}, f)
    with open(os.path.join(model_dir, "config.json"), "w", encoding="utf-8") as f:
        json.dump({"image_size": image_size}, f)
    with open(os.path.join(model_dir, "metrics.json"), "w", encoding="utf-8") as f:
        json.dump(metrics, f)

def _load_active_model():
    conn = _db()
    cur = conn.cursor()
    cur.execute("SELECT model_id FROM active_model WHERE singleton_id = 1")
    row = cur.fetchone()
    model_id = row["model_id"] if row else None
    if not model_id:
        conn.close()
        return None
    cur.execute("SELECT model_dir, labels_json, image_size FROM models WHERE id = ? AND status = 'ready'", (model_id,))
    mrow = cur.fetchone()
    conn.close()
    if not mrow:
        return None
    model_dir = mrow["model_dir"]
    labels = json.loads(mrow["labels_json"])["labels"]
    image_size = int(mrow["image_size"])
    model = tf.saved_model.load(model_dir)
    infer = model.signatures["serving_default"]
    return {"model_id": model_id, "infer": infer, "labels": labels, "image_size": image_size}

ACTIVE_MODEL_CACHE = {"loaded_at": 0.0, "data": None}
ACTIVE_MODEL_TTL_SEC = float(os.environ.get("COMMUNITY_AI_MODEL_CACHE_TTL", "10"))

def _get_active_model_cached():
    now = time.time()
    if ACTIVE_MODEL_CACHE["data"] is None or (now - ACTIVE_MODEL_CACHE["loaded_at"]) > ACTIVE_MODEL_TTL_SEC:
        ACTIVE_MODEL_CACHE["data"] = _load_active_model()
        ACTIVE_MODEL_CACHE["loaded_at"] = now
    return ACTIVE_MODEL_CACHE["data"]

def _train_job(training_id: str):
    with TRAIN_LOCK:
        conn = _db()
        cur = conn.cursor()
        cur.execute("SELECT params_json FROM trainings WHERE id = ?", (training_id,))
        row = cur.fetchone()
        if not row:
            conn.close()
            return
        params = json.loads(row["params_json"])
        cur.execute("UPDATE trainings SET status = 'running', error = NULL WHERE id = ?", (training_id,))
        conn.commit()
        conn.close()

        try:
            image_size = int(params.get("image_size", DEFAULT_IMAGE_SIZE))
            batch_size = int(params.get("batch_size", DEFAULT_BATCH_SIZE))
            epochs = int(params.get("epochs", DEFAULT_EPOCHS))
            lr = float(params.get("learning_rate", DEFAULT_LEARNING_RATE))
            seed = int(params.get("seed", DEFAULT_SEED))

            conn = _db()
            labels = _get_labels(conn)
            if len(labels) < 2:
                raise RuntimeError("Need at least 2 distinct labels to train")
            label_to_idx = {l: i for i, l in enumerate(labels)}

            train_pairs = _fetch_examples(conn, "train")
            val_pairs = _fetch_examples(conn, "val")
            test_pairs = _fetch_examples(conn, "test")
            conn.close()

            if len(train_pairs) < 10:
                raise RuntimeError("Need at least 10 training examples to train")

            train_ds = _build_dataset(train_pairs, label_to_idx, image_size, batch_size, True, seed)
            val_ds = _build_dataset(val_pairs, label_to_idx, image_size, batch_size, False, seed) if val_pairs else None
            test_ds = _build_dataset(test_pairs, label_to_idx, image_size, batch_size, False, seed) if test_pairs else None

            model, base = _build_model(len(labels), image_size, lr)

            callbacks = [
                tf.keras.callbacks.EarlyStopping(monitor="val_accuracy" if val_ds else "accuracy", patience=3, restore_best_weights=True),
            ]

            history1 = model.fit(
                train_ds,
                validation_data=val_ds,
                epochs=max(1, epochs),
                callbacks=callbacks,
                verbose=1
            )

            _fine_tune(model, base, lr)
            history2 = model.fit(
                train_ds,
                validation_data=val_ds,
                epochs=max(1, max(1, epochs // 2)),
                callbacks=callbacks,
                verbose=1
            )

            metrics = {"train": {}, "val": {}, "test": {}, "history": {}}
            metrics["history"]["phase1"] = {k: [float(x) for x in v] for k, v in history1.history.items()}
            metrics["history"]["phase2"] = {k: [float(x) for x in v] for k, v in history2.history.items()}

            train_eval = model.evaluate(train_ds, verbose=0)
            metrics["train"] = {"loss": float(train_eval[0]), "accuracy": float(train_eval[1])}

            if val_ds:
                val_eval = model.evaluate(val_ds, verbose=0)
                metrics["val"] = {"loss": float(val_eval[0]), "accuracy": float(val_eval[1])}

            if test_ds:
                test_eval = model.evaluate(test_ds, verbose=0)
                metrics["test"] = {"loss": float(test_eval[0]), "accuracy": float(test_eval[1])}

            model_dir = os.path.join(MODELS_DIR, f"model_{_uuid()}")
            _save_model_bundle(model, model_dir, labels, image_size, metrics)

            conn = _db()
            cur = conn.cursor()
            cur.execute("""
                UPDATE trainings
                SET status = 'completed', error = NULL, model_dir = ?, metrics_json = ?
                WHERE id = ?
            """, (model_dir, json.dumps(metrics), training_id))
            model_id = _uuid()
            cur.execute("""
                INSERT INTO models(id, created_at, training_id, status, model_dir, metrics_json, labels_json, image_size)
                VALUES (?, ?, ?, 'ready', ?, ?, ?, ?)
            """, (model_id, _now(), training_id, model_dir, json.dumps(metrics), json.dumps({"labels": labels}), image_size))
            cur.execute("UPDATE active_model SET model_id = ? WHERE singleton_id = 1", (model_id,))
            conn.commit()
            conn.close()

            ACTIVE_MODEL_CACHE["data"] = None
            ACTIVE_MODEL_CACHE["loaded_at"] = 0.0

        except Exception as e:
            conn = _db()
            cur = conn.cursor()
            cur.execute("UPDATE trainings SET status = 'failed', error = ? WHERE id = ?", (str(e), training_id))
            conn.commit()
            conn.close()

app = FastAPI(title=APP_NAME)

class TrainRequest(BaseModel):
    image_size: Optional[int] = DEFAULT_IMAGE_SIZE
    batch_size: Optional[int] = DEFAULT_BATCH_SIZE
    epochs: Optional[int] = DEFAULT_EPOCHS
    learning_rate: Optional[float] = DEFAULT_LEARNING_RATE
    seed: Optional[int] = DEFAULT_SEED

@app.on_event("startup")
def startup():
    _ensure_dirs()
    _init_db()

@app.get("/health")
def health():
    conn = _db()
    counts = _count_examples(conn)
    conn.close()
    active = _get_active_model_cached()
    return {
        "status": "ok",
        "examples": counts,
        "active_model_id": active["model_id"] if active else None
    }

@app.post("/upload/csv")
async def upload_csv(
    file: UploadFile = File(...),
    contributor: Optional[str] = Form(None),
    val_split: float = Form(DEFAULT_VAL_SPLIT),
    test_split: float = Form(DEFAULT_TEST_SPLIT),
    seed: int = Form(DEFAULT_SEED),
):
    if not file.filename.lower().endswith(".csv"):
        raise HTTPException(status_code=400, detail="Only CSV files are accepted here")
    upload_id = _uuid()
    stored_path = os.path.join(UPLOADS_DIR, f"{upload_id}_{os.path.basename(file.filename)}")
    try:
        size = _read_upload_to_disk(file, stored_path)
        sha = _sha256_file(stored_path)
        conn = _db()
        cur = conn.cursor()
        cur.execute("""
            INSERT INTO uploads(id, created_at, filename, content_type, size_bytes, sha256, stored_path, status, error)
            VALUES (?, ?, ?, ?, ?, ?, ?, 'stored', NULL)
        """, (upload_id, _now(), file.filename, file.content_type, size, sha, stored_path))
        conn.commit()
        conn.close()

        df = _load_csv_from_path(stored_path)
        if len(df) < 1:
            raise ValueError("No rows found in CSV")

        splits = _split_assign(len(df), val_split=val_split, test_split=test_split, seed=seed)
        df["split"] = splits

        conn = _db()
        cur = conn.cursor()
        inserted = 0
        for _, r in df.iterrows():
            ex_id = _uuid()
            cur.execute("""
                INSERT INTO examples(id, created_at, source_upload_id, image_path, label, split, contributor, metadata_json)
                VALUES (?, ?, ?, ?, ?, ?, ?, ?)
            """, (ex_id, _now(), upload_id, r["image_path"], r["label"], r["split"], contributor, json.dumps({"source": "csv"})))
            inserted += 1
        conn.commit()
        counts = _count_examples(conn)
        conn.close()

        return {"upload_id": upload_id, "inserted_examples": inserted, "examples": counts}
    except Exception as e:
        conn = _db()
        cur = conn.cursor()
        cur.execute("UPDATE uploads SET status = 'failed', error = ? WHERE id = ?", (str(e), upload_id))
        conn.commit()
        conn.close()
        raise HTTPException(status_code=400, detail=str(e))

@app.post("/upload/zip_images_with_csv")
async def upload_zip_images_with_csv(
    file: UploadFile = File(...),
    contributor: Optional[str] = Form(None),
    csv_filename: str = Form("labels.csv"),
    val_split: float = Form(DEFAULT_VAL_SPLIT),
    test_split: float = Form(DEFAULT_TEST_SPLIT),
    seed: int = Form(DEFAULT_SEED),
):
    if not file.filename.lower().endswith(".zip"):
        raise HTTPException(status_code=400, detail="Only ZIP files are accepted here")
    upload_id = _uuid()
    stored_path = os.path.join(UPLOADS_DIR, f"{upload_id}_{os.path.basename(file.filename)}")
    extract_dir = os.path.join(DATASETS_DIR, f"dataset_{upload_id}")
    try:
        size = _read_upload_to_disk(file, stored_path)
        sha = _sha256_file(stored_path)

        os.makedirs(extract_dir, exist_ok=True)
        _extract_zip(stored_path, extract_dir)

        csv_path = os.path.join(extract_dir, csv_filename)
        if not os.path.exists(csv_path):
            raise ValueError(f"CSV file '{csv_filename}' not found inside ZIP")

        df = _load_csv_from_path(csv_path)
        df = _resolve_image_paths(df, extract_dir)
        if df.empty:
            raise ValueError("No valid image paths found after resolving within ZIP")

        splits = _split_assign(len(df), val_split=val_split, test_split=test_split, seed=seed)
        df["split"] = splits

        conn = _db()
        cur = conn.cursor()
        cur.execute("""
            INSERT INTO uploads(id, created_at, filename, content_type, size_bytes, sha256, stored_path, status, error)
            VALUES (?, ?, ?, ?, ?, ?, ?, 'stored', NULL)
        """, (upload_id, _now(), file.filename, file.content_type, size, sha, stored_path))

        inserted = 0
        for _, r in df.iterrows():
            ex_id = _uuid()
            cur.execute("""
                INSERT INTO examples(id, created_at, source_upload_id, image_path, label, split, contributor, metadata_json)
                VALUES (?, ?, ?, ?, ?, ?, ?, ?)
            """, (ex_id, _now(), upload_id, r["image_path"], r["label"], r["split"], contributor, json.dumps({"source": "zip"})))
            inserted += 1

        conn.commit()
        counts = _count_examples(conn)
        conn.close()

        return {"upload_id": upload_id, "dataset_dir": extract_dir, "inserted_examples": inserted, "examples": counts}
    except Exception as e:
        conn = _db()
        cur = conn.cursor()
        cur.execute("UPDATE uploads SET status = 'failed', error = ? WHERE id = ?", (str(e), upload_id))
        conn.commit()
        conn.close()
        try:
            if os.path.isdir(extract_dir):
                shutil.rmtree(extract_dir, ignore_errors=True)
        except Exception:
            pass
        raise HTTPException(status_code=400, detail=str(e))

@app.post("/contribute/example")
async def contribute_example(
    image: UploadFile = File(...),
    label: str = Form(...),
    contributor: Optional[str] = Form(None),
    split: str = Form("train"),
):
    split = split.lower().strip()
    if split not in {"train", "val", "test"}:
        raise HTTPException(status_code=400, detail="split must be one of: train, val, test")
    ext = os.path.splitext(image.filename)[1].lower()
    if ext not in ALLOWED_IMAGE_EXTS:
        raise HTTPException(status_code=400, detail="Unsupported image extension")
    upload_id = _uuid()
    stored_path = os.path.join(UPLOADS_DIR, f"{upload_id}_{os.path.basename(image.filename)}")
    try:
        size = _read_upload_to_disk(image, stored_path)
        sha = _sha256_file(stored_path)

        conn = _db()
        cur = conn.cursor()
        cur.execute("""
            INSERT INTO uploads(id, created_at, filename, content_type, size_bytes, sha256, stored_path, status, error)
            VALUES (?, ?, ?, ?, ?, ?, ?, 'stored', NULL)
        """, (upload_id, _now(), image.filename, image.content_type, size, sha, stored_path))

        ex_id = _uuid()
        cur.execute("""
            INSERT INTO examples(id, created_at, source_upload_id, image_path, label, split, contributor, metadata_json)
            VALUES (?, ?, ?, ?, ?, ?, ?, ?)
        """, (ex_id, _now(), upload_id, stored_path, label, split, contributor, json.dumps({"source": "single"})))

        conn.commit()
        counts = _count_examples(conn)
        conn.close()

        return {"upload_id": upload_id, "example_id": ex_id, "examples": counts}
    except Exception as e:
        conn = _db()
        cur = conn.cursor()
        cur.execute("UPDATE uploads SET status = 'failed', error = ? WHERE id = ?", (str(e), upload_id))
        conn.commit()
        conn.close()
        raise HTTPException(status_code=400, detail=str(e))

@app.get("/examples/stats")
def examples_stats():
    conn = _db()
    counts = _count_examples(conn)
    labels = _get_labels(conn)
    conn.close()
    return {"examples": counts, "labels": labels}

@app.post("/train")
def train(req: TrainRequest, background: BackgroundTasks):
    training_id = _uuid()
    params = req.model_dump()
    conn = _db()
    cur = conn.cursor()
    cur.execute("""
        INSERT INTO trainings(id, created_at, status, error, params_json, model_dir, metrics_json)
        VALUES (?, ?, 'queued', NULL, ?, NULL, NULL)
    """, (training_id, _now(), json.dumps(params)))
    conn.commit()
    conn.close()

    background.add_task(_train_job, training_id)
    return {"training_id": training_id, "status": "queued", "params": params}

@app.get("/train/{training_id}")
def training_status(training_id: str):
    conn = _db()
    cur = conn.cursor()
    cur.execute("SELECT * FROM trainings WHERE id = ?", (training_id,))
    row = cur.fetchone()
    conn.close()
    if not row:
        raise HTTPException(status_code=404, detail="Training not found")
    out = dict(row)
    if out.get("params_json"):
        out["params"] = json.loads(out["params_json"])
        del out["params_json"]
    if out.get("metrics_json"):
        out["metrics"] = json.loads(out["metrics_json"])
        del out["metrics_json"]
    return out

@app.get("/models")
def list_models(limit: int = 20):
    limit = max(1, min(200, int(limit)))
    conn = _db()
    cur = conn.cursor()
    cur.execute("SELECT id, created_at, training_id, status, model_dir, metrics_json, labels_json, image_size FROM models ORDER BY created_at DESC LIMIT ?", (limit,))
    rows = cur.fetchall()
    conn.close()
    out = []
    for r in rows:
        d = dict(r)
        d["metrics"] = json.loads(d["metrics_json"]) if d.get("metrics_json") else None
        d["labels"] = json.loads(d["labels_json"])["labels"] if d.get("labels_json") else []
        d.pop("metrics_json", None)
        d.pop("labels_json", None)
        out.append(d)
    return {"models": out}

@app.post("/models/{model_id}/activate")
def activate_model(model_id: str):
    conn = _db()
    cur = conn.cursor()
    cur.execute("SELECT id FROM models WHERE id = ? AND status = 'ready'", (model_id,))
    row = cur.fetchone()
    if not row:
        conn.close()
        raise HTTPException(status_code=404, detail="Model not found or not ready")
    cur.execute("UPDATE active_model SET model_id = ? WHERE singleton_id = 1", (model_id,))
    conn.commit()
    conn.close()
    ACTIVE_MODEL_CACHE["data"] = None
    ACTIVE_MODEL_CACHE["loaded_at"] = 0.0
    return {"active_model_id": model_id}

@app.get("/models/active")
def active_model():
    active = _get_active_model_cached()
    if not active:
        return {"active_model_id": None}
    return {"active_model_id": active["model_id"], "labels": active["labels"], "image_size": active["image_size"]}

@app.post("/predict")
async def predict(image: UploadFile = File(...)):
    active = _get_active_model_cached()
    if not active:
        raise HTTPException(status_code=400, detail="No active model. Train a model first.")
    ext = os.path.splitext(image.filename)[1].lower()
    if ext not in ALLOWED_IMAGE_EXTS:
        raise HTTPException(status_code=400, detail="Unsupported image extension")

    data = await image.read()
    if len(data) > MAX_UPLOAD_BYTES:
        raise HTTPException(status_code=413, detail="Upload too large")

    img = tf.io.decode_image(data, channels=3, expand_animations=False)
    img = tf.image.convert_image_dtype(img, tf.float32)
    img = tf.image.resize(img, [active["image_size"], active["image_size"]])
    img = tf.expand_dims(img, 0)

    infer = active["infer"]
    out = infer(tf.constant(img))
    probs = None
    for k, v in out.items():
        probs = v.numpy()[0]
        break
    if probs is None:
        raise HTTPException(status_code=500, detail="Inference failed")

    labels = active["labels"]
    topk = int(min(5, len(labels)))
    idx = np.argsort(-probs)[:topk]
    preds = [{"label": labels[int(i)], "prob": float(probs[int(i)])} for i in idx]
    return {"model_id": active["model_id"], "predictions": preds}

